Code.Terraform:
```hcl
# Security Hub を有効にする
resource "aws_securityhub_account" "<example_resource_name>" {}

# 重要: チェックに合格するには、少なくとも1つの標準を有効にしてください
resource "aws_securityhub_standards_subscription" "<example_resource_name>_fsbp" {
  standards_arn = "arn:aws:securityhub:<REGION>::standards/aws-foundational-security-best-practices/v/1.0.0" # AWS FSBP を有効にします
}
```
